import Vue from 'vue'
import VueRouter from 'vue-router'
// 导入需要的组件
import Home from '@/views/Home/Home.vue'
import Photo from '@/views/Photo/Photo'
import Homepage from '@/views/Homepage/Homepage'
import Messages from '@/views/Messages/Messages'
import About from '@/views/About/About'
import Navigation from '@/views/Navigation/Navigation'
import Personal from '@/views/Personal/Personal'
import Test from '@/views/Test/Test'
// 把VueRouter 安装为Vue的插件
Vue.use(VueRouter)
// 路由规则的数组
const routes = [
  // 定义首页的路由规则
  { path: '/', redirect: '/home' },
  {
    path: '/home',
    component: Home,
    // 重定向
    redirect: '/home/homepage',
    children: [
      { path: '/home/homepage', component: Homepage },
      { path: '/home/photo', component: Photo },
      { path: '/home/messages', component: Messages },
      {
        path: '/home/about',
        component: About,
        children: [
          { path: '/home/about/next', component: Test }
        ]
      },
      { path: '/home/navigation', component: Navigation },
      { path: '/home/personal', component: Personal },
      // 关于站长的路由规则
      { path: '/home/7-1', component: Homepage },
      { path: '/home/7-2', component: Homepage }
    ]
  }

]
// 创建路由对象
const router = new VueRouter({
  routes
})
// 向外共享路由
export default router
