<template>
  <div class="imgupload-container">
<!--    上传列表放大的模态框-->
    <el-dialog :visible.sync="dialogVisible">
      <img width="100%" height="100%" :src="dialogImageUrl" :alt="dialogImageName">
    </el-dialog>
    <el-upload
      class="upload-demo"
      ref="upload"
      :action="uploadURL"
      :on-preview="handlePreview"
      :on-remove="handleRemove"
      :file-list="fileList"
      :on-success="onSuccess"
      :on-error="onError"
      :before-upload="beforeUpload"
      :on-exceed="onExceed"
      list-type="picture-card"
      :limit="limit"
      :auto-upload="false">
      <el-button slot="trigger" size="small" type="success"
       style="font-size: 3em;background: #fbfdff;color: black;border: #fbfdff;
       opacity: 1!important;
">+</el-button>
      <el-button style="margin-left: 10px;margin-top: 9.5em;height: 3em;"
                 size="small" type="primary" @click="submitUpload">留下你的足迹</el-button>
      <div slot="tip" class="el-upload__tip" style="color: #67c23a">上传图片大小不得超过 15 MB  且最大只能同时上传{{ limit }}张图片</div>
    </el-upload>
  </div>
</template>

<script>
// import ElImageViewer from 'element-ui/packages/image/src/image-viewer'
export default {
  name: 'ImgUpload',
  props: ['uploadURL'],
  data() {
    return {
      // 图片列表
      fileList: [],
      // 最大上传的照片张数
      limit: 1,
      // 上传图片的模态框是否显示
      dialogVisible: false,
      // 上传图片点击显示的图片
      dialogImageUrl: '',
      // 上传图片点击显示的名字，如果图片加载不出来的话
      dialogImageName: ''
    }
  },
  created() {
    // console.log(this.fileList)
  },
  methods: {
    // 提交表单的钩子
    submitUpload() {
      console.log(this.fileList.length)
      if (this.fileList.length === 0) {
        this.$message({
          message: '请选择上传图片！',
          type: 'error'
        })
      }
      this.$refs.upload.submit()
    },
    // 上传文件之前的钩子，参数为上传的文件，若返回 false 或者返回 Promise 且被 reject则停止上传 function(file)
    beforeUpload(file) {
      // console.log(file.size)
      // console.log(file.type)
      // 判断大于15 mb 阻止上传
      if (file.size > 15728640) {
        this.$message({
          message: '文件过大,请重试！',
          type: 'error'
        })
        return false
      } else {
        return true
      }
    },
    // 文件列表移除文件时的钩子  function(file, fileList)
    handleRemove(file, fileList) {
      // console.log(file, fileList)
      this.$message({
        message: '移除成功！',
        type: 'success'
      })
    },
    // 文件上传成功时的钩子 function(response, file, fileList)
    onSuccess(response, file, fileList) {
      // console.log(response)
      // 传给父元素
      this.$emit('uploadChange', { changeURL: response.imgservepath })

      this.$message({
        message: '恭喜您，上传成功！',
        type: 'success'
      })
      // 上传成功清空列表
      this.fileList = []
    },
    // 文件上传失败时的钩子  function(err, file, fileList)
    onError(err, file, fileList) {
      console.log(err)
      this.$message({
        message: '很抱歉，上传失败，请重试！',
        type: 'error'
      })
    },
    // 点击文件列表中已上传的文件时的钩子 function(file) 图片放大
    handlePreview(file) {
      // console.log(file.name)
      this.dialogImageUrl = file.url
      this.dialogImageName = file.name
      this.dialogVisible = true
    },
    // on-exceed 文件超出个数限制时的钩子 function(files, fileList)
    onExceed(files, fileList) {
      // console.log(fileList.length)
      if (fileList.length === 1) {
        this.$message({
          message: '上传图片超过 1 个！！！',
          type: 'warning'
        })
      }
    }
  }
}
</script>
<style lang="less" scoped>
.imgupload-container{
  /deep/.el-upload--picture-card{
    //background: red;
    opacity: 0.5;
  }
}
</style>
