<template>
  <div class="photo-container"
       :style="{'background-image':'url('+photoBg+')'}">
    <!--    <h3>photo 组件&#45;&#45;完善中</h3>-->
    <div class="container">
      <ImgUpload :upload-u-r-l="uploadURL"
                 @uploadChange="uploadChanges"
      ></ImgUpload>
    </div>
    <div class="demo-image__preview container">
      <p style="margin-left: 1em;"><i style="color: #67c23a">照片墙 :</i></p>
      <el-image v-for="item in url" :key="item.id"
                style="width: 150px; height: 150px;float: left;margin-left: 1em;
        margin-bottom: 1em;padding: 0.1em;border: 0.4em solid #67c23a"
                :src="item"
                :preview-src-list="srcList">
      </el-image>
    </div>
  </div>
</template>

<script>

import ImgUpload from '@/components/ImgUpload/ImgUpload'
import { getPhotoImgAPI } from '@/api/photoAPI'

export default {
  name: 'Photo',
  data() {
    return {
      // 上传地址
      uploadURL: 'http://49.233.53.82:5050/imgupload',
      // uploadURL: 'http://127.0.0.1:5050/imgupload',
      // 原始图片 数组
      url: [],
      // 放大后的图片 数组
      srcList: [],
      photoBg: 'http://49.233.53.82:5050/1645197350765-bg1.jpg'
    }
  },
  created() {
    this.getImg()
    // this.uploadChange()
    this.photoBackground()
  },
  methods: {
    async getImg() {
      const { data: res } = await getPhotoImgAPI()
      // console.log(res)
      console.log(res[0].imgservepath)
      for (let i = 0; i < res.length; i++) {
        this.url.push(res[i].imgservepath)
        this.srcList.push(res[i].imgservepath)
      }
      // console.log(this.url)
    },
    // 当用户上传图片时
    uploadChanges(e) {
      // console.log(555)
      // console.log(e.changeURL)
      // console.log(this.url)
      this.url = [e.changeURL, ...this.url]
      // console.log(this.url)
      this.srcList = [e.changeURL, ...this.srcList]
    },
    photoBackground() {
      setInterval(() => {
      //   console.log(this.url[Math.floor(Math.random() * this.url.length)])
      // const sentenceTypeItem = this.url[Math.floor(Math.random() * this.url.length)]
        this.photoBg = this.url[Math.floor(Math.random() * this.url.length)]
      }, 3000)
    }
  },
  components: { ImgUpload }
}
</script>

