  //background-image: url("http://49.233.53.82:5050/1645197350765-bg1.jpg");
  background-size: cover;
  height: 100vh;
  padding-top: 0.5em;

  .demo-image__preview {
    //float: left;
    padding: 1em;
    //background: #dcccb5;
  }
}
</style>
