import Textcard from '@/components/Textcard/Textcard'
export default {
  name: 'Homepage',
  components: { Textcard, Music },
  created() {
    this.gitFamous()
    // window.setInterval(this.gitFamous()
    //   , 6000)
  },
  data() {
    return {
      // homeBg: document.body.clientHeight,
      famous: '幸运的人一生都在被童年治愈，不幸的人一生都在治愈童年。',
      // 备用名言数组
      famousSpare: ['谎言重复一千遍就成了真理。',
        '呐，做人呢，最重要的是开心，你饿不饿，我煮碗面给你吃啊。',
        '淅淅沥沥的雨，即便能填满路上的水坑，也填不满心中的空洞。', '当我沉默的时候，我觉得很充实，当我开口说话，就感到了空虚。',
        '似水流年是一个人所有的一切，只有这个东西，才真正归你所有。'],
      browserWidth: document.body.clientWidth,
      // 分辨率的宽度
      ResolutionWidth: window.screen.width
    }
  },
  methods: {
    async gitFamous() {
      const famousStr = []
      // 请求参数类型封装
      const sentenceTypeAPI = ['a', 'b', 'c', 'd', 'e', 'f', 'g', 'h', 'i', 'j', 'k']
      // 跨域问题未解决
      // for (let i = 0; i < 5; i++) {
      // 从数组中随机抽取一个数
      const sentenceTypeItem = sentenceTypeAPI[Math.floor(Math.random() * sentenceTypeAPI.length)]
      // 请求首页名言
      const { data: res } = await getFamousAPI(sentenceTypeItem, 'utf-8')
      // console.log(res)
      famousStr.push(res.hitokoto)
      // }
      // console.log(famousStr)
      this.famousSpare = [...famousStr, ...this.famousSpare]
      // console.log(this.famousSpare)
      // typed 插件渲染打字效果
      // eslint-disable-next-line no-new
      new Typed('.famous', {
        strings: this.famousSpare,
        startDelay: 300,
        typeSpeed: 150,
        loop: true,
        backSpeed: 50,
        showCursor: true
      })
    }
  }

}
